// Express bootstrap. The fixture exposes a /health probe and a
// POST /auth/login route that issues an HS256 JWT to a fixture-grade
// demo user. Real user storage is out of scope; the route shape and
// JWT signing are what callers (and the QA harness) exercise.

import express from "express";
import jwt from "jsonwebtoken";

// Fixture-grade demo credentials. Real auth would hash + look up a user
// row; this is just enough for the harness to exercise the route shape.
const DEMO_USERNAME = "demo";
const DEMO_PASSWORD = "password";

// Dev fallback is deliberately obvious so it cannot be mistaken for a
// production secret. In any real deploy, JWT_SECRET must be set.
const DEV_FALLBACK_SECRET = "dev-only-not-for-production";

function getJwtSecret() {
    return process.env.JWT_SECRET || DEV_FALLBACK_SECRET;
}

export function createApp() {
    const app = express();
    app.use(express.json());

    app.get("/health", (_req, res) => {
        res.json({ ok: true });
    });

    app.post("/auth/login", (req, res) => {
        // Body may be undefined (no Content-Type), a non-object (e.g. a
        // bare string survived express.json), or missing fields. Treat
        // every shape we can't authenticate as a plain 401 — never crash,
        // never leak whether the username existed.
        const body = req.body;
        const username = body && typeof body === "object" ? body.username : undefined;
        const password = body && typeof body === "object" ? body.password : undefined;

        if (typeof username !== "string" || typeof password !== "string") {
            return res.status(401).json({ error: "invalid credentials" });
        }

        if (username !== DEMO_USERNAME || password !== DEMO_PASSWORD) {
            return res.status(401).json({ error: "invalid credentials" });
        }

        const token = jwt.sign(
            { sub: username },
            getJwtSecret(),
            { algorithm: "HS256", expiresIn: "15m" }
        );

        return res.status(200).json({ token });
    });

    return app;
}

// When run directly, listen. When imported (e.g. by tests), just export.
if (import.meta.url === `file://${process.argv[1]}`) {
    const port = Number(process.env.PORT ?? 3000);
    createApp().listen(port, () => {
        // eslint-disable-next-line no-console
        console.log(`server listening on :${port}`);
    });
}

// Server tests. Covers the bootstrap smoke check, the /auth/login
// happy path (real signed JWT round-trips back), and the 401 paths
// (wrong creds and malformed bodies).

import { describe, it, expect } from "vitest";
import jwt from "jsonwebtoken";
import request from "supertest";
import { createApp } from "./index.js";

// Mirror the dev fallback in server/index.js so we can verify-decode the
// token issued by the route when no JWT_SECRET is set in the test env.
const DEV_FALLBACK_SECRET = "dev-only-not-for-production";

function secret() {
    return process.env.JWT_SECRET || DEV_FALLBACK_SECRET;
}

describe("server bootstrap", () => {
    it("creates an app instance", () => {
        const app = createApp();
        expect(typeof app.listen).toBe("function");
    });
});

describe("POST /auth/login", () => {
    it("returns 200 and a string token for valid credentials", async () => {
        const app = createApp();
        const res = await request(app)
            .post("/auth/login")
            .send({ username: "demo", password: "password" })
            .set("Content-Type", "application/json");

        expect(res.status).toBe(200);
        expect(typeof res.body.token).toBe("string");
        expect(res.body.token.length).toBeGreaterThan(0);

        // The token must be a real HS256 JWT signed with our secret and
        // carry sub=username. A stub string would fail verify().
        const decoded = jwt.verify(res.body.token, secret(), { algorithms: ["HS256"] });
        expect(decoded.sub).toBe("demo");
    });

    it("returns 401 with an error field for wrong password", async () => {
        const app = createApp();
        const res = await request(app)
            .post("/auth/login")
            .send({ username: "demo", password: "wrong" })
            .set("Content-Type", "application/json");

        expect(res.status).toBe(401);
        expect(typeof res.body.error).toBe("string");
        expect(res.body.token).toBeUndefined();
    });

    it("returns 401 with an error field for unknown username", async () => {
        const app = createApp();
        const res = await request(app)
            .post("/auth/login")
            .send({ username: "nobody", password: "password" })
            .set("Content-Type", "application/json");

        expect(res.status).toBe(401);
        expect(typeof res.body.error).toBe("string");
    });

    it("returns 401 (not 500) for a missing body", async () => {
        const app = createApp();
        const res = await request(app).post("/auth/login");

        expect(res.status).toBe(401);
        expect(typeof res.body.error).toBe("string");
    });

    it("returns 401 (not 500) for a malformed body missing fields", async () => {
        const app = createApp();
        const res = await request(app)
            .post("/auth/login")
            .send({ username: "demo" })
            .set("Content-Type", "application/json");

        expect(res.status).toBe(401);
        expect(typeof res.body.error).toBe("string");
    });
});

// LoginForm: controlled username/password form that POSTs JSON to
// /auth/login and surfaces the resulting token (or error) to its caller.
//
// Contract (matches the backend implemented in parallel by @backend):
//   Request:  POST /auth/login  Content-Type: application/json
//             body: { username, password }
//   Success:  200 { token }     -> calls onLogin(token), shows success line.
//   Failure:  non-200 with { error }
//                              -> renders inline error, calls onError(message).
//   Network: fetch throws       -> renders generic network error, onError fires.
//
// Props (all optional):
//   onLogin(token: string)   - invoked on a 200 with a token in the body.
//   onError(message: string) - invoked on any non-2xx or network failure.
//
// The component keeps the token in local state too so it works standalone
// (e.g. for the test harness) without requiring the parent to wire callbacks.

import React, { useState } from "react";

const INITIAL = { username: "", password: "" };

export default function LoginForm({ onLogin, onError } = {}) {
    const [fields, setFields] = useState(INITIAL);
    const [status, setStatus] = useState("idle"); // idle | submitting | success | error
    const [errorMessage, setErrorMessage] = useState("");
    const [token, setToken] = useState(null);

    const update = (name) => (event) => {
        setFields((prev) => ({ ...prev, [name]: event.target.value }));
    };

    const surfaceError = (message) => {
        setStatus("error");
        setErrorMessage(message);
        if (typeof onError === "function") {
            try {
                onError(message);
            } catch {
                // Swallow caller-side throws so the component never throws
                // back into React's render tree from an event handler.
            }
        }
    };

    const handleSubmit = async (event) => {
        event.preventDefault();
        if (status === "submitting") return;

        setStatus("submitting");
        setErrorMessage("");

        let response;
        try {
            response = await fetch("/auth/login", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    username: fields.username,
                    password: fields.password,
                }),
            });
        } catch {
            // Network-level failure (DNS, offline, CORS preflight reject, ...).
            surfaceError("Network error. Please check your connection and try again.");
            return;
        }

        // Defensive JSON parse: backend contract is JSON on both paths,
        // but a 5xx HTML page from a proxy shouldn't crash the form.
        let payload = null;
        try {
            payload = await response.json();
        } catch {
            payload = null;
        }

        if (!response.ok) {
            const message =
                (payload && typeof payload.error === "string" && payload.error) ||
                `Login failed (${response.status})`;
            surfaceError(message);
            return;
        }

        const receivedToken = payload && typeof payload.token === "string" ? payload.token : null;
        if (!receivedToken) {
            // 200 without a token violates the contract — treat as an error
            // so the UI doesn't claim success while leaving the caller empty-handed.
            surfaceError("Login response missing token.");
            return;
        }

        setToken(receivedToken);
        setStatus("success");
        if (typeof onLogin === "function") {
            try {
                onLogin(receivedToken);
            } catch {
                // See surfaceError for rationale.
            }
        }
    };

    const submitting = status === "submitting";

    return (
        <form className="login-form" onSubmit={handleSubmit} aria-busy={submitting} noValidate>
            <div className="login-form__field">
                <label htmlFor="login-username">Username</label>
                <input
                    id="login-username"
                    name="username"
                    type="text"
                    autoComplete="username"
                    value={fields.username}
                    onChange={update("username")}
                    disabled={submitting}
                    required
                />
            </div>

            <div className="login-form__field">
                <label htmlFor="login-password">Password</label>
                <input
                    id="login-password"
                    name="password"
                    type="password"
                    autoComplete="current-password"
                    value={fields.password}
                    onChange={update("password")}
                    disabled={submitting}
                    required
                />
            </div>

            <button type="submit" disabled={submitting}>
                {submitting ? "Logging in..." : "Log in"}
            </button>

            {status === "error" && errorMessage ? (
                <p className="login-form__error" role="alert">
                    {errorMessage}
                </p>
            ) : null}

            {status === "success" && token ? (
                <p className="login-form__success" role="status">
                    Logged in.
                </p>
            ) : null}
        </form>
    );
}

// App: thin shell that hosts the LoginForm. The h1 is kept so the
// existing App.test.jsx smoke test (which only asserts the export is a
// function) continues to pass, and so the page has a single top-level
// heading for screen readers.

import React, { useState } from "react";
import LoginForm from "./LoginForm.jsx";

export default function App() {
    const [token, setToken] = useState(null);

    return (
        <div className="app">
            <h1>node-react-auth fixture</h1>
            <LoginForm onLogin={setToken} />
            {token ? <p className="app__token">Token received.</p> : null}
        </div>
    );
}

// @vitest-environment jsdom
//
// LoginForm tests. Uses jsdom (set via the file-local pragma above so the
// sibling App.test.jsx smoke test stays in the default node environment)
// and @testing-library/react, both of which are already present in the
// fixture's node_modules tree.

import React from "react";
import { describe, it, expect, beforeEach, afterEach, vi } from "vitest";
import { render, screen, fireEvent, cleanup, waitFor } from "@testing-library/react";

import LoginForm from "./LoginForm.jsx";

const okResponse = (body) => ({
    ok: true,
    status: 200,
    json: async () => body,
});

const errResponse = (status, body) => ({
    ok: false,
    status,
    json: async () => body,
});

describe("LoginForm", () => {
    beforeEach(() => {
        global.fetch = vi.fn();
    });

    afterEach(() => {
        cleanup();
        vi.restoreAllMocks();
        delete global.fetch;
    });

    it("renders username and password inputs plus a submit button", () => {
        render(<LoginForm />);

        const username = screen.getByLabelText(/username/i);
        const password = screen.getByLabelText(/password/i);
        const submit = screen.getByRole("button", { name: /log in/i });

        expect(username).toBeTruthy();
        expect(username.tagName).toBe("INPUT");
        expect(password).toBeTruthy();
        expect(password.getAttribute("type")).toBe("password");
        expect(submit).toBeTruthy();
        expect(submit.getAttribute("type")).toBe("submit");
    });

    it("POSTs JSON {username, password} to /auth/login on submit and calls onLogin with the returned token", async () => {
        global.fetch.mockResolvedValueOnce(okResponse({ token: "tok-abc" }));
        const onLogin = vi.fn();

        render(<LoginForm onLogin={onLogin} />);

        fireEvent.change(screen.getByLabelText(/username/i), {
            target: { value: "alice" },
        });
        fireEvent.change(screen.getByLabelText(/password/i), {
            target: { value: "s3cret" },
        });
        fireEvent.click(screen.getByRole("button", { name: /log in/i }));

        await waitFor(() => expect(global.fetch).toHaveBeenCalledTimes(1));

        const [url, init] = global.fetch.mock.calls[0];
        expect(url).toBe("/auth/login");
        expect(init.method).toBe("POST");
        expect(init.headers["Content-Type"]).toBe("application/json");
        expect(JSON.parse(init.body)).toEqual({
            username: "alice",
            password: "s3cret",
        });

        await waitFor(() => expect(onLogin).toHaveBeenCalledWith("tok-abc"));
        expect(screen.getByRole("status").textContent).toMatch(/logged in/i);
    });

    it("renders an inline error and invokes onError when the server returns a non-ok response", async () => {
        global.fetch.mockResolvedValueOnce(errResponse(401, { error: "Invalid credentials" }));
        const onError = vi.fn();
        const onLogin = vi.fn();

        render(<LoginForm onLogin={onLogin} onError={onError} />);

        fireEvent.change(screen.getByLabelText(/username/i), {
            target: { value: "alice" },
        });
        fireEvent.change(screen.getByLabelText(/password/i), {
            target: { value: "wrong" },
        });
        fireEvent.click(screen.getByRole("button", { name: /log in/i }));

        await waitFor(() => expect(onError).toHaveBeenCalledWith("Invalid credentials"));
        expect(onLogin).not.toHaveBeenCalled();

        const alert = await screen.findByRole("alert");
        expect(alert.textContent).toBe("Invalid credentials");
    });

    it("surfaces a network-level fetch failure without throwing", async () => {
        global.fetch.mockRejectedValueOnce(new TypeError("Failed to fetch"));
        const onError = vi.fn();

        render(<LoginForm onError={onError} />);

        fireEvent.change(screen.getByLabelText(/username/i), {
            target: { value: "alice" },
        });
        fireEvent.change(screen.getByLabelText(/password/i), {
            target: { value: "s3cret" },
        });
        fireEvent.click(screen.getByRole("button", { name: /log in/i }));

        await waitFor(() => expect(onError).toHaveBeenCalledTimes(1));
        const message = onError.mock.calls[0][0];
        expect(typeof message).toBe("string");
        expect(message.toLowerCase()).toContain("network");

        const alert = await screen.findByRole("alert");
        expect(alert.textContent).toMatch(/network/i);
    });
});

// Fixture-local Vitest config.
//
// Without this file, `vitest run` walks up the directory tree looking for
// a config and finds the L3/L4 E2E harness config at
// `.claude/tests/e2e/vitest.config.ts`, which restricts `include` to
// `specs/**/*.spec.ts` and ends up matching nothing inside the fixture.
//
// We only need to (a) stop the walk-up and (b) keep Vitest's sensible
// defaults — particularly the default `include` of
// `**/*.{test,spec}.?(c|m)[jt]s?(x)` so both `server/index.test.js` and
// `client/src/*.test.jsx` are picked up by a single `npm test` from the
// fixture root.
//
// Per-file `// @vitest-environment jsdom` pragmas drive the DOM
// environment in LoginForm.test.jsx; everything else stays on the default
// node environment.

import { defineConfig } from "vitest/config";

export default defineConfig({
    test: {},
});

// @vitest-environment jsdom
//
// LoginForm tests.
//
// We deliberately stay off @testing-library/react: the fixture's
// node_modules is reconciled to declared deps by npm (so anything not in
// client/package.json gets pruned), and the spec is happy with the
// "drive the component via react-dom/test-utils + ReactDOM.createRoot"
// path. The file-local jsdom pragma above keeps the sibling
// App.test.jsx smoke test in the default node environment.

import React from "react";
import ReactDOM from "react-dom/client";
import { act } from "react-dom/test-utils";
import { describe, it, expect, beforeEach, afterEach, vi } from "vitest";

import LoginForm from "./LoginForm.jsx";

// ---- helpers ---------------------------------------------------------------

let container;
let root;

function mount(ui) {
    container = document.createElement("div");
    document.body.appendChild(container);
    root = ReactDOM.createRoot(container);
    act(() => {
        root.render(ui);
    });
    return container;
}

function unmount() {
    if (root) {
        act(() => {
            root.unmount();
        });
        root = null;
    }
    if (container && container.parentNode) {
        container.parentNode.removeChild(container);
    }
    container = null;
}

function queryByLabelText(root, labelText) {
    const labels = Array.from(root.querySelectorAll("label"));
    const label = labels.find((el) =>
        el.textContent.toLowerCase().includes(labelText.toLowerCase()),
    );
    if (!label) return null;
    const forId = label.getAttribute("for");
    if (forId) return root.querySelector(`#${forId}`);
    return label.querySelector("input, select, textarea");
}

function getSubmitButton(root) {
    return root.querySelector('button[type="submit"]');
}

function setInputValue(input, value) {
    // React tracks the previous value off the DOM node to dedupe synthetic
    // onChange events; we have to use the descriptor setter so React sees
    // a fresh value when we dispatch the input event.
    const proto = Object.getPrototypeOf(input);
    const setter = Object.getOwnPropertyDescriptor(proto, "value").set;
    setter.call(input, value);
    input.dispatchEvent(new Event("input", { bubbles: true }));
}

async function flush() {
    // Resolve promises queued by fetch().then(...) chains.
    await act(async () => {
        await Promise.resolve();
        await Promise.resolve();
    });
}

const okResponse = (body) => ({
    ok: true,
    status: 200,
    json: async () => body,
});

const errResponse = (status, body) => ({
    ok: false,
    status,
    json: async () => body,
});

// ---- tests -----------------------------------------------------------------

describe("LoginForm", () => {
    beforeEach(() => {
        global.fetch = vi.fn();
    });

    afterEach(() => {
        unmount();
        vi.restoreAllMocks();
        delete global.fetch;
    });

    it("renders username and password inputs plus a submit button", () => {
        const root = mount(<LoginForm />);

        const username = queryByLabelText(root, "username");
        const password = queryByLabelText(root, "password");
        const submit = getSubmitButton(root);

        expect(username).toBeTruthy();
        expect(username.tagName).toBe("INPUT");
        expect(password).toBeTruthy();
        expect(password.getAttribute("type")).toBe("password");
        expect(submit).toBeTruthy();
        expect(submit.textContent.toLowerCase()).toContain("log in");
    });

    it("POSTs JSON {username, password} to /auth/login on submit and calls onLogin with the returned token", async () => {
        global.fetch.mockResolvedValueOnce(okResponse({ token: "tok-abc" }));
        const onLogin = vi.fn();

        const root = mount(<LoginForm onLogin={onLogin} />);

        setInputValue(queryByLabelText(root, "username"), "alice");
        setInputValue(queryByLabelText(root, "password"), "s3cret");

        await act(async () => {
            getSubmitButton(root).click();
        });
        await flush();

        expect(global.fetch).toHaveBeenCalledTimes(1);
        const [url, init] = global.fetch.mock.calls[0];
        expect(url).toBe("/auth/login");
        expect(init.method).toBe("POST");
        expect(init.headers["Content-Type"]).toBe("application/json");
        expect(JSON.parse(init.body)).toEqual({
            username: "alice",
            password: "s3cret",
        });

        expect(onLogin).toHaveBeenCalledWith("tok-abc");

        const status = root.querySelector('[role="status"]');
        expect(status).toBeTruthy();
        expect(status.textContent.toLowerCase()).toContain("logged in");
    });

    it("renders an inline error and invokes onError when the server returns a non-ok response", async () => {
        global.fetch.mockResolvedValueOnce(errResponse(401, { error: "Invalid credentials" }));
        const onError = vi.fn();
        const onLogin = vi.fn();

        const root = mount(<LoginForm onLogin={onLogin} onError={onError} />);

        setInputValue(queryByLabelText(root, "username"), "alice");
        setInputValue(queryByLabelText(root, "password"), "wrong");

        await act(async () => {
            getSubmitButton(root).click();
        });
        await flush();

        expect(onError).toHaveBeenCalledWith("Invalid credentials");
        expect(onLogin).not.toHaveBeenCalled();

        const alert = root.querySelector('[role="alert"]');
        expect(alert).toBeTruthy();
        expect(alert.textContent).toBe("Invalid credentials");
    });

    it("surfaces a network-level fetch failure without throwing", async () => {
        global.fetch.mockRejectedValueOnce(new TypeError("Failed to fetch"));
        const onError = vi.fn();

        const root = mount(<LoginForm onError={onError} />);

        setInputValue(queryByLabelText(root, "username"), "alice");
        setInputValue(queryByLabelText(root, "password"), "s3cret");

        await act(async () => {
            getSubmitButton(root).click();
        });
        await flush();

        expect(onError).toHaveBeenCalledTimes(1);
        const message = onError.mock.calls[0][0];
        expect(typeof message).toBe("string");
        expect(message.toLowerCase()).toContain("network");

        const alert = root.querySelector('[role="alert"]');
        expect(alert).toBeTruthy();
        expect(alert.textContent.toLowerCase()).toContain("network");
    });
});

