async function submit(root) {
    // Click the submit button and let the async handler drain inside one
    // act() so React applies every queued state update before we assert.
    await act(async () => {
        getSubmitButton(root).click();
    });
    // The handler chains await fetch().then(json => setState(...)); the
    // outer act() above only awaits the synchronous click. We need a
    // second act() turn so React commits the state updates queued by the
    // microtask resolution of fetch() and .json().
    await act(async () => {
        await Promise.resolve();
        await Promise.resolve();
        await Promise.resolve();
    });
}
